// ═══════════════════════════════════════════════════════
// Step 4: Build RAG Request gegen Mitbewerber Collection
// Generisch: Verwendet die Collection-ID aus der Config
// ═══════════════════════════════════════════════════════
const fact = $input.item.json;
const config = fact.config;

return {
  ...fact,
  retrievalRequestBody: JSON.stringify({
    collection_names: [config.competitorRagCollection],
    query: fact.rag_query,
    k: config.ragTopK
  })
};
